package org.apache.commons.csv;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.csv.steps"
)
public class CucumberTest {
}

package org.apache.commons.csv.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.Assert;
import java.io.IOException;
import java.util.Map;

public class StepDefs {
    private CSVParser parser;
    private Map<String, Integer> headerMap;
    private Exception exception;

    @Given("a CSV parser initialized with CSV data {string} and DEFAULT format")
    public void a_CSV_parser_initialized_with_CSV_data_and_DEFAULT_format(String csvData) throws IOException {
        try {
            parser = CSVParser.parse(csvData, CSVFormat.DEFAULT);
        } catch (Exception e) {
            exception = e;
        }
    }

    @When("I request the header map")
    public void i_request_the_header_map() {
        try {
            headerMap = parser.getHeaderMap();
        } catch (Exception e) {
            exception = e;
        }
    }

    @Then("the result should be null")
    public void the_result_should_be_null() {
        if (exception != null) {
             throw new RuntimeException("Exception occurred while retrieving header map", exception);
        }
        Assert.assertNull("Header map should be null", headerMap);
    }
}
